#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool solve(vector<int>& nums, int target) {
        vector<vector<bool>> dp(nums.size() + 1, vector<bool>(target + 1));
        for (int i = 0; i <= nums.size(); i++) {
            dp[i][0] = true;
        }
        for (int i = 1; i <= nums.size(); i++) {
            for (int j = 1; j <= target; j++) {
                dp[i][j] = dp[i - 1][j];
                if (j >= nums[i - 1]) {
                    dp[i][j] = dp[i][j] || dp[i - 1][j - nums[i - 1]];
                }
            }
        }
        return dp.back().back();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, target;
    cin >> n >> target;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    Solution sol;
    bool ans = sol.solve(nums, target);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
